INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Online booking widget$q$, $q$A public, embeddable booking page lets customers choose a service, provider, and appointment time without creating an account.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Google Calendar sync$q$, $q$Two-way synchronization keeps each provider's personal calendar automatically updated with new bookings and cancellations.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Video meeting integration$q$, $q$Built-in Jitsi and Google Meet links can be attached to appointments for virtual consultations.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$SMS and email reminders$q$, $q$Automated notification workflows send confirmations, reminders, and cancellation notices to customers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$REST API and SDK$q$, $q$A documented API and multi-lingual SDK let developers build custom booking experiences on top of the core engine.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$CMS integrations$q$, $q$Official plugins embed the booking widget directly into WordPress, Joomla, and Drupal sites.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Multi-provider scheduling$q$, $q$Businesses can configure multiple staff members or providers, each with independent services, working hours, and booking rules.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Self-hosted data ownership$q$, $q$All customer and appointment data stays on infrastructure the business controls, with no third-party vendor storing bookings.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Completely free with no licensing fees, seat limits, or commission on bookings$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Full data ownership since everything runs on the business's own server$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Open-source codebase can be customized and extended without vendor restrictions$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Actively maintained with a large community and translations into 20+ languages$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Requires the business or its IT team to handle hosting, backups, and security updates$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$No official vendor-run cloud version with a guaranteed uptime commitment$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Initial setup requires familiarity with PHP, MySQL, and web server configuration$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Fewer built-in marketing and payment features compared to polished commercial SaaS competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Is Easy!Appointments really free?$q$, $q$Yes. The software is released under the GPL-3.0 open-source license and can be downloaded, installed, and used for personal or commercial purposes at no cost, with no per-booking commission.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Do I need technical skills to install it?$q$, $q$Some technical knowledge is required, since it needs a web server running Apache or Nginx, PHP, and a MySQL or MariaDB database. The official Docker image simplifies deployment for those comfortable with containers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Does it sync with Google Calendar?$q$, $q$Yes, Easy!Appointments offers two-way synchronization with Google Calendar so provider calendars stay current automatically.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Can customers pay online when booking?$q$, $q$Payment collection at the time of booking is supported through available integrations, alongside automated confirmation and reminder notifications.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Is there a hosted or managed version?$q$, $q$There is no official SaaS cloud edition, but the maintainer and community offer optional managed hosting and support services on a custom-quote basis.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$What languages does the interface support?$q$, $q$Community translations cover more than 20 languages, including English, German, Greek, Spanish, French, Italian, Japanese, and Simplified Chinese, with automatic browser-based language detection.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Independent service providers$q$, $q$Hairdressers, tutors, consultants, and therapists use it to run a professional online booking page without paying a monthly subscription.$q$, $q$Freelancers and solo practitioners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Clinics with strict data requirements$q$, $q$Medical and dental practices self-host the system to keep patient appointment data on infrastructure they fully control.$q$, $q$Healthcare and wellness providers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Agencies building custom booking flows$q$, $q$Development agencies use the REST API and SDK to embed or extend booking functionality inside client websites and apps.$q$, $q$Developers and digital agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited providers, services, and appointments","No commission on bookings","Google Calendar sync","REST API access","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$Premium Services$q$, $q$Custom quote$q$, $q$One-time or contract$q$, NULL, $q$["Managed hosting","White-labeling","Custom feature development","Data migration from other booking systems","Dedicated support contracts"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Easy!Appointments is a self-hosted, open-source scheduling system that businesses install on their own server to accept online bookings. It is maintained by developer Alex Tselegidis and a community of contributors, with a codebase dating back to 2013 and more than 3,000 stars on GitHub.$q$, $q$The application gives customers a public booking page to select a service, provider, and appointment time, while staff manage everything from an administrative dashboard, including working hours, booking rules, and provider calendars synced with Google Calendar.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include two-way Google Calendar sync, SMS and email reminders, Jitsi and Google Meet video links for virtual appointments, a REST API, and official plugins for WordPress, Joomla, and Drupal.$q$, $q$The system supports multiple providers and services with independent working plans, customizable booking rules such as buffer time between appointments, and administrative reporting on booking activity across the business.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The software itself is entirely free under the GPL-3.0 license, with no per-user fees, no booking caps, and no commission on transactions. Costs are limited to the web hosting infrastructure the business chooses to run it on.$q$, $q$Organizations that prefer not to self-manage the server can purchase optional custom-quoted services from the maintainer's team, including managed hosting, white-labeling, custom development, and data migration.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1c4c7eb8-4d91-4764-a260-79baa4f12ad4', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Multi-game server management$q$, $q$Deploy and control game servers for Counter-Strike, Minecraft, Team Fortress, and dozens of other titles from one interface.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Voice server support$q$, $q$Manages TeamSpeak 3 voice servers alongside game servers within the same panel.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Automated deployment$q$, $q$Symlink-based installation reduces disk usage and setup time compared to duplicating full game files per server.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Crash monitoring and auto-restart$q$, $q$Services are continuously monitored, with automatic recovery if a game or voice server process crashes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Webspace and database management$q$, $q$Handles Apache2 or Nginx webspace hosting and MySQL/MariaDB databases independently or alongside game servers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Built-in CMS$q$, $q$A lightweight content management system lets hosting providers publish pages and news directly from the panel.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Responsive interface$q$, $q$The web dashboard adapts to desktop and mobile screens for on-the-go server administration.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Centralized image-server updates$q$, $q$Game server software can be updated centrally from an image server rather than patched machine by machine.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Completely free and open source with no licensing costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Supports both game servers and voice servers in a single panel$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Automation and symlink-based deployment reduce administrative overhead$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Includes a built-in CMS, useful for hosting providers who need a public storefront$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$No official hosted or managed cloud version$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Interface and documentation are primarily oriented toward English and German speakers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Uses an older SSH/RCON architecture rather than modern container-based isolation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Requires self-managed server infrastructure and technical setup knowledge$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Is Easy-Wi free to use?$q$, $q$Yes, Easy-Wi is fully open source and free, with no licensing fee or per-server charge for the panel software itself.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$What games does Easy-Wi support?$q$, $q$It supports dozens of game servers, including Counter-Strike, Minecraft, and Team Fortress, along with TeamSpeak 3 voice servers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Who created Easy-Wi?$q$, $q$Easy-Wi was created by developer Alexander Dörwald, based in Leipzig, Germany, and is maintained as an open-source project on GitHub.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Does Easy-Wi offer a hosted cloud version?$q$, $q$No, there is no official SaaS or managed cloud edition. Organizations must run Easy-Wi on their own server infrastructure.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Can Easy-Wi manage more than just game servers?$q$, $q$Yes, it also manages TeamSpeak 3 voice servers, webspace hosting on Apache2 or Nginx, and MySQL/MariaDB databases.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$What languages does the panel support?$q$, $q$The interface and documentation are available in English and German.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Commercial game hosting providers$q$, $q$Hosting companies use Easy-Wi to provision, automate, and resell game and voice server capacity across a fleet of machines.$q$, $q$Game hosting businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Gaming clans and communities$q$, $q$Clans self-host Counter-Strike or Minecraft servers and manage them through a single dashboard without paying a third-party host.$q$, $q$Gaming communities and clan admins$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$LAN party and event organizers$q$, $q$Organizers spin up and manage temporary game servers for events using the panel's automated deployment tools.$q$, $q$Event and LAN party organizers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited game and voice servers on your own infrastructure","Webspace and database management","Built-in CMS","Automated crash monitoring and restart","Community support via GitHub and Discord"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Easy-Wi is an open-source, self-hosted web interface created by developer Alexander Dörwald in Leipzig, Germany, for managing game servers, voice servers, and general hosting infrastructure from a single control panel.$q$, $q$It acts as middleware between an administrative web dashboard and the actual servers, communicating over SSH and RCON to deploy, monitor, and automatically restart game and voice server processes across one or more machines.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The panel supports dozens of games including Counter-Strike, Minecraft, and Team Fortress, as well as TeamSpeak 3 voice servers, webspace management for Apache2 and Nginx, and MySQL/MariaDB database administration.$q$, $q$Automation features include symlink-based deployment to reduce disk usage and install time, centralized image-server updates for game files, service monitoring with automatic crash recovery, and a built-in lightweight CMS for hosting-provider storefronts or community pages.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Easy-Wi is completely free and open source, with no licensing fee, subscription, or per-server charge published anywhere on the project's site or repositories.$q$, $q$There is no hosted SaaS version; organizations provide their own server infrastructure, so the only real cost is the hosting capacity needed to run the game and voice servers being managed.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9f50961f-98ec-4271-b1ef-2f486257a4a5', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Multi-channel reservations$q$, $q$Collects bookings from the restaurant's website, social media, Google, and the Eat App partner network into one live view.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Table and floor plan management$q$, $q$A visual floor plan lets host staff seat walk-ins and reservations while tracking table turns in real time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Digital waitlist$q$, $q$Manages walk-in guests with automated text notifications when their table becomes ready.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Guest CRM$q$, $q$Builds detailed guest profiles with visit history, preferences, and spend for personalized service and marketing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$WhatsApp and email marketing$q$, $q$Sends automated reservation confirmations and targeted marketing campaigns through WhatsApp and email.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Mobile apps for iOS and Android$q$, $q$Lets managers and hosts view and edit reservations and monitor metrics from anywhere on the floor.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$POS and phone system integration$q$, $q$Connects with point-of-sale and PBX phone systems to enrich guest profiles with order and call history.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Loyalty and prepayment tools$q$, $q$Higher tiers add loyalty program management, prepayments, and deposit collection to reduce no-shows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Transparent fixed monthly pricing with no per-cover or per-reservation fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Free plan available for small venues with up to 100 covers per month$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Combines reservations, table management, and CRM/marketing in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Dedicated mobile apps let staff manage the floor without being tied to a terminal$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Higher tiers needed to unlock unlimited covers and full WhatsApp/marketing volume$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$POS and phone integrations cost extra on lower-priced plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Enterprise pricing for multi-location groups is not publicly published$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Some competitors offer larger built-in diner discovery networks$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Does Eat App have a free plan?$q$, $q$Yes, Eat App offers a free plan supporting up to 100 covers per month with a chat inbox and custom booking forms.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$How much does Eat App cost?$q$, $q$Paid plans start at $99 per month for Starter, rising to $199 per month for Essential and $389 per month for Pro, with roughly 30% savings when billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Does Eat App charge per reservation?$q$, $q$No, Eat App uses fixed monthly pricing with no per-cover or per-reservation fees, unlike some reservation marketplaces.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Is there a mobile app?$q$, $q$Yes, Eat App offers dedicated apps for iPhone and Android for managing reservations and guests on the go.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Can Eat App integrate with our POS system?$q$, $q$Yes, POS integration is available as an add-on on lower tiers and is included on the Pro plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Who is Eat App best suited for?$q$, $q$Eat App suits independent restaurants, multi-location restaurant groups, and hotel food and beverage outlets that want reservations, table management, and guest CRM in one platform.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Independent restaurants reducing no-shows$q$, $q$Single-location restaurants use the waitlist, reminders, and prepayment tools to cut no-show rates and improve table turns.$q$, $q$Independent restaurant owners and managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Multi-location restaurant groups$q$, $q$Groups centralize guest data and reservations across several venues to standardize service and marketing.$q$, $q$Restaurant groups and hospitality chains$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Hotel food and beverage outlets$q$, $q$Hotels use Eat App to manage on-site restaurant reservations alongside guest CRM and marketing tools.$q$, $q$Hotel F&B managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Free$q$, $q$$0/month$q$, $q$Monthly$q$, NULL, $q$["Up to 100 covers per month","Chat inbox","Custom forms and surveys"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Starter$q$, $q$$99/month ($69/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 300 covers per month","100 WhatsApp conversations","Email marketing suite"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Essential$q$, $q$$199/month ($159/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited covers","Waitlist management","250 WhatsApp conversations","Loyalty suite"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Pro$q$, $q$$389/month ($299/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited covers","500 WhatsApp conversations","All add-ons included","Dedicated success manager"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Centralized multi-location guest data","Enterprise security features","Custom integrations and onboarding"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Eat App is a cloud-based reservation, table management, and guest CRM platform for restaurants, hotels, and hospitality venues, founded by Nezar Kadhem and headquartered in Dubai, United Arab Emirates after originating in Bahrain.$q$, $q$The company has raised roughly $31.6 million in funding across multiple rounds, including a 2022 round led by Middle East Venture Partners, 500 Startups, and Derayah Venture Capital, positioning it as an established hospitality-tech company serving venues internationally.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include multi-channel reservation collection, a visual floor plan and table management module, digital waitlist with text notifications, and a guest CRM that tracks visit history, preferences, and spend for personalized marketing.$q$, $q$Eat App also offers iPhone and Android apps for on-the-floor management, WhatsApp and email marketing tools, and integrations with POS and PBX phone systems to enrich guest profiles.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Eat App offers a Free plan for up to 100 covers per month, followed by Starter ($99/mo, ~$69/mo annually), Essential ($199/mo, ~$159/mo annually) with unlimited covers, and Pro ($389/mo, ~$299/mo annually) with all add-ons and a dedicated success manager.$q$, $q$A custom-priced Enterprise plan is available for restaurant groups and hotel chains needing centralized data across multiple locations, and annual billing saves roughly 30 percent versus paying monthly.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
