INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('58340ae3-bb72-49c9-8eb1-38e05b4918b4', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Repository-aware skill generation$q$, $q$Analyzes commit history and existing configuration to generate project-specific skills, rules, and commands for AI coding agents.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Reviewable pull-request automation$q$, $q$Proposes generated configuration as pull requests for human review rather than modifying a repository silently.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Issue-comment commands$q$, $q$Supports commands like analyze, setup, and audit triggered directly from GitHub issue comments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$AgentShield security scanning$q$, $q$Runs roughly 100 static analysis rules against agent configs, MCP servers, and tool permissions to catch misconfigurations.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Multi-model adversarial testing$q$, $q$An optional red-team, blue-team, and auditor pipeline simulates attacks against an agent's guardrails using multiple AI models.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Cross-harness compatibility$q$, $q$Works across Claude Code, Codex, Cursor, and OpenCode rather than locking teams into a single agent vendor.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Open-source skills library$q$, $q$Provides a free, MIT-licensed library of hundreds of pre-built skills, agents, and commands covering planning, testing, and code review.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Enterprise governance$q$, $q$Enterprise tier adds SSO-ready governance, audit logs, and custom policy packs for organization-wide rollout.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Free tier and open-source core make it accessible before committing to a paid plan$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Combines context generation and security scanning for AI agents in one workflow$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Works across multiple AI coding agent platforms instead of a single vendor$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Pull-request-based automation keeps a human in the review loop$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Very new project (2026 origin), with a shorter track record than established dev tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Private repository features require a paid Pro or Enterprise plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Enterprise pricing is not published and requires direct sales contact$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Effectiveness depends on the quality of a repository's existing commit history and documentation$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$What does ECC Tools actually do?$q$, $q$It analyzes a repository's history and configuration to generate project-specific skills, rules, and security checks for AI coding agents, proposing them as reviewable pull requests.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Is ECC Tools free?$q$, $q$Yes, there is a free tier for public repositories with up to 10 analyses per month, built on a free, MIT-licensed open-source core.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$How much does the paid plan cost?$q$, $q$The Pro tier costs $19 per active developer seat per month, or $190 per seat per year when billed annually.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$What is AgentShield?$q$, $q$AgentShield is ECC Tools' security scanning component, running around 100 rules against AI agent configurations, MCP servers, and tool permissions to detect vulnerabilities and misconfigurations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Which AI coding agents does it support?$q$, $q$ECC Tools works across Claude Code, Codex, Cursor, and OpenCode rather than being limited to a single agent platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Who built ECC Tools?$q$, $q$It was created by developer Affaan Mustafa, originating at a Claude Code hackathon hosted by Cerebral Valley and Anthropic in early 2026.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Engineering teams standardizing agent workflows$q$, $q$Teams use ECC Tools to give every AI coding agent session consistent project context and conventions instead of starting from zero each time.$q$, $q$Software engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Security-conscious organizations adopting AI agents$q$, $q$Organizations use AgentShield to audit agent configurations and MCP server permissions before rolling out AI coding tools broadly.$q$, $q$Security and platform engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Multi-agent development shops$q$, $q$Teams using more than one AI coding assistant apply ECC Tools to keep skills and security policies consistent across all of them.$q$, $q$Teams using multiple AI coding agent platforms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Free$q$, $q$$0/month$q$, $q$Monthly$q$, NULL, $q$["Public repositories only","10 analyses per month","200 commits scanned per run","Issue-comment triggered pull requests","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Pro$q$, $q$$19/seat/month ($190/seat/year)$q$, $q$Monthly or annual$q$, NULL, $q$["Private repository analysis","50 analyses per active seat","1,000 commits per run","AgentShield-backed config scanning","Auto-triggers on large pushes and PRs","Priority email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Unlimited analyses","5,000 commits per run","SSO-ready governance and audit logs","Custom rules and policy packs","Dedicated onboarding and SLA"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ECC Tools is an open agent harness platform created by developer Affaan Mustafa, originating at a 2026 Claude Code hackathon hosted by Cerebral Valley and Anthropic, that analyzes a repository and generates project-specific skills, rules, hooks, and security checks for AI coding agents.$q$, $q$It is built on top of a large open-source library of pre-built skills, agents, and commands, and adds a hosted GitHub App plus a dedicated security scanner called AgentShield for auditing AI agent configurations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform generates reusable skills, rules, and commands based on a repository's commit history and existing configuration, and proposes them as reviewable pull requests rather than silent automated changes.$q$, $q$AgentShield runs roughly 100 static analysis rules against agent configs, MCP servers, and tool permissions, with an optional multi-model red-team/blue-team/auditor pipeline to simulate adversarial attacks against an agent's guardrails.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ECC Tools offers a Free tier for public repositories with 10 analyses per month, a Pro tier at $19 per seat per month (or $190 per seat yearly) for private repos and deeper audits, and a custom-priced Enterprise tier for organization-wide governance and rollout.$q$, $q$All tiers build on the free, MIT-licensed open-source repository, so teams can adopt the core skills library at no cost before upgrading for private-repo automation and security scanning.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b66550cc-ba3f-493f-afe3-06c11c362355', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Multi-model AI shopping simulation$q$, $q$Runs products through GPT-4, Claude, Gemini, and Perplexity simultaneously to see how each model ranks them against competitors.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Automated listing optimization$q$, $q$Rewrites product titles, descriptions, and structured data to improve how AI agents evaluate a listing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Competitor gap analysis$q$, $q$Identifies specific attribute, pricing, or trust-signal gaps causing a product to lose to competitors in agent rankings.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Shopify and WooCommerce integration$q$, $q$Connects directly to a merchant's existing product catalog for ongoing analysis and optimization.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$UCP Playground and validator$q$, $q$Lets merchants test and validate product listings against the emerging Universal Commerce Protocol.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$MCP API access$q$, $q$Provides a documented Model Context Protocol API for programmatically querying agent-visibility data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Per-model win-rate reporting$q$, $q$Breaks down how often each product is selected by AI agents versus competitors, model by model.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Free audit lets merchants baseline their AI shopping agent visibility before paying$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Simulates multiple leading AI models rather than testing against just one$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Automated rewriting turns diagnosis directly into optimized listing content$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Native Shopify App Store presence simplifies setup for existing merchants$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Company founding details, headquarters, and funding are not publicly disclosed$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Mid-tier Compete plan pricing is not publicly published$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Focused primarily on Shopify and WooCommerce, limiting fit for other platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$AI shopping agent behavior can change as underlying models are updated, requiring ongoing re-optimization$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$What does écentic do?$q$, $q$écentic simulates how AI shopping agents like ChatGPT, Claude, Gemini, and Perplexity evaluate products, diagnoses why listings lose to competitors, and automatically rewrites content to improve agent selection rates.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Is there a free version of écentic?$q$, $q$Yes, écentic offers a Free Scan that provides a baseline audit of a merchant's current AI shopping agent win rate at no cost.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$How much does écentic cost?$q$, $q$The Dominate plan is priced at $449 per month; the Compete tier's price is not publicly disclosed, and Enterprise pricing is custom.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Which ecommerce platforms does écentic support?$q$, $q$écentic integrates natively with Shopify through the Shopify App Store and also supports WooCommerce.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$What is the Universal Commerce Protocol (UCP)?$q$, $q$UCP is an emerging protocol for structuring product data so AI shopping agents can evaluate it consistently; écentic provides a Playground and validator to test listings against it.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Who is écentic built for?$q$, $q$It is built for ecommerce merchants and brand teams, particularly on Shopify and WooCommerce, who want to improve visibility and win rate when AI agents make purchasing decisions.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$DTC brands optimizing for AI shopping agents$q$, $q$Direct-to-consumer brands use écentic to rewrite product listings so they are more likely to be recommended by AI shopping assistants.$q$, $q$Ecommerce brand and marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Shopify merchants diagnosing lost sales$q$, $q$Merchants use the platform to understand why competitors are chosen over them when shoppers use AI agents to compare products.$q$, $q$Shopify and WooCommerce store owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Agencies managing AI-visibility strategy$q$, $q$Digital agencies use écentic's per-model reporting and MCP API to manage AI shopping visibility across multiple merchant clients.$q$, $q$Ecommerce agencies and consultants$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Free Scan$q$, $q$$0$q$, $q$One-time audit$q$, NULL, $q$["Baseline AI shopping agent win-rate audit","Initial competitor comparison"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Compete$q$, $q$Contact for pricing$q$, $q$Monthly$q$, NULL, $q$["Ongoing AI agent visibility tracking","Competitor comparison"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Dominate$q$, $q$$449/month$q$, $q$Monthly$q$, NULL, $q$["Continuous multi-model simulations","Automated content optimization","UCP support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Large catalog support","Custom integrations","Dedicated account management"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$écentic is an AI ecommerce optimization platform that simulates how AI shopping agents such as ChatGPT, Claude, Gemini, and Perplexity evaluate and rank products, then diagnoses why a listing loses to competitors and rewrites it to improve its odds of being selected.$q$, $q$It connects primarily to Shopify (also supporting WooCommerce) and runs products through multiple large language models simultaneously to produce a per-model breakdown of win rates and attribute gaps.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include multi-model AI agent simulation, automated rewriting of product titles, descriptions, and structured data, and competitor gap analysis broken down by AI model.$q$, $q$The platform also offers a UCP Playground and validator for testing compliance with the Universal Commerce Protocol, and a documented MCP API for programmatic access to agent-visibility data.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$écentic offers a free Free Scan audit to establish a baseline AI agent win rate, a mid-tier Compete plan, and a Dominate plan priced at $449 per month with continuous simulations and automated optimization.$q$, $q$An Enterprise tier is available for larger catalogs at custom pricing, and discounted partner deals exist for companies backed by Y Combinator and Techstars.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('51409ee6-9c94-4bbc-977d-bb6ef59e11c5', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Markdown editor with live preview$q$, $q$Compose posts using Markdown with a real-time preview of the rendered output.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$ActivityPub federation$q$, $q$Supports the ActivityPub protocol so an Ech0 instance can interact with the wider Fediverse rather than staying isolated.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Rich media and video embeds$q$, $q$Supports images, audio, and video, with built-in embed parsing for YouTube and Bilibili links.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Passwordless authentication$q$, $q$Supports Passkey and WebAuthn login alongside OAuth2 and OpenID Connect for identity provider integration.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Open API and webhooks$q$, $q$Exposes a documented API and webhook system for integrating Ech0 with external tools and automations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$MCP server integration$q$, $q$Includes a built-in Model Context Protocol server that lets AI assistants interact with an instance's content.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$AI Recap and RAG chat$q$, $q$Generates AI-powered digests of recent posts and offers a retrieval-augmented chat interface over a user's own timeline.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Lightweight, multi-platform deployment$q$, $q$Runs on Linux, Windows, and ARM devices including the Raspberry Pi, with single-command Docker deployment.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Completely free and open source with no ads, tracking, or subscription fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Very lightweight, able to run on low-power hardware like a Raspberry Pi$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Unusually rich feature set for a small project, including MCP and AI-powered features$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Supports ActivityPub federation, avoiding lock-in to a single platform$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$No official hosted or managed cloud version; requires self-hosting$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Maintained primarily by a single developer, which carries bus-factor risk$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$AGPL-3.0 licensing requires source disclosure for modified public deployments$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Documentation and community support skew toward a Chinese-speaking audience$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Is Ech0 free to use?$q$, $q$Yes, Ech0 is fully free and open source under the AGPL-3.0-or-later license, with no ads, tracking, or subscription fees.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Who develops Ech0?$q$, $q$Ech0 is developed by a programmer known as lin-snow (L1nSn0w), with the source code hosted at github.com/lin-snow/Ech0.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Can Ech0 run on a Raspberry Pi?$q$, $q$Yes, Ech0 is designed to be lightweight and supports ARM devices, including the Raspberry Pi, alongside Linux and Windows.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Does Ech0 support federation with other platforms?$q$, $q$Yes, Ech0 supports the ActivityPub protocol, allowing it to federate with the broader Fediverse rather than operating as an isolated silo.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$What AI features does Ech0 include?$q$, $q$Ech0 includes a Model Context Protocol server, AI-generated Recap digests of recent posts, and a retrieval-augmented generation chat feature over a user's own content.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Is there a hosted version of Ech0?$q$, $q$No, there is no official managed cloud version; Ech0 must be self-hosted, though deployment via Docker can take under a minute.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Privacy-conscious individuals sharing personal updates$q$, $q$Users self-host Ech0 to publish short posts and links without ads, tracking, or dependence on a third-party platform.$q$, $q$Self-hosting enthusiasts and privacy-focused individuals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Developers experimenting with AI-integrated publishing$q$, $q$Developers use Ech0's MCP server and RAG chat to build AI assistants that interact with a personal content archive.$q$, $q$Developers and hobbyist tinkerers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Low-power home server deployments$q$, $q$Hobbyists run Ech0 on Raspberry Pi or other low-power hardware as a lightweight personal publishing node.$q$, $q$Home lab and ARM device users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited posts and media","ActivityPub federation","MCP server and AI Recap/RAG chat","Community support via GitHub and QQ group"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$Commercial License$q$, $q$Custom (contact maintainer)$q$, $q$Negotiated$q$, NULL, $q$["Embed Ech0 in a proprietary product","No AGPL source-disclosure requirement"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Ech0 is a free, open-source, self-hosted microblogging platform created by developer lin-snow for individuals who want to publish short posts, thoughts, and links while retaining full ownership of their data.$q$, $q$It supports the ActivityPub protocol for federation with the broader Fediverse and is designed to be lightweight enough to run on low-power hardware such as a Raspberry Pi.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Ech0 provides a Markdown editor with live preview, tag management, RSS export, rich media embedding with YouTube and Bilibili support, and a lightweight comment and like system.$q$, $q$Advanced features include OAuth2/OIDC authentication, Passkey/WebAuthn login, an open API with webhooks, a CLI toolchain, and an integrated Model Context Protocol server that powers AI-generated Recap digests and RAG-based chat over a user's own content.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Ech0 is fully free and open source under the AGPL-3.0-or-later license, with no ads, tracking, or subscription fees for self-hosted instances.$q$, $q$A separate commercial license is available for organizations wanting to embed Ech0 in a proprietary product without AGPL's source-disclosure requirement, priced through direct negotiation with the maintainer rather than a published rate.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0bc21b7f-dfe2-4c44-a7ad-9cac54962d52', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$Electronic health record$q$, $q$Core clinical documentation, charting, and e-prescribing with formulary checking for outpatient practices.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$Patient portal and messaging$q$, $q$Lets patients access records and communicate securely with providers through eClinicalMessenger.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$Mobile access$q$, $q$The eClinicalMobile app gives physicians chart access and patient interaction tools away from the office.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$Practice management and billing$q$, $q$Optional module adds scheduling, billing, and revenue-cycle tools on top of the core EHR.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$Revenue Cycle Management as a Service$q$, $q$Outsourced billing service covering claims processing, denial management, and appeals for a percentage of collections.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$eClinicalWorks P2P health information exchange$q$, $q$Enables peer-to-peer data exchange between providers for continuity of care.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$Eva AI virtual assistant$q$, $q$AI-driven assistant introduced in the V12 platform to support clinical documentation workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$Reporting and registry tools$q$, $q$eBO View business intelligence and registry reporting help practices track performance and meet regulatory requirements.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$Largest privately held ambulatory EHR vendor in the US with a very large installed base$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$Straightforward per-provider pricing without large upfront enterprise contracts$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$Broad bundled feature set including patient portal, messaging, and mobile access in the base price$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$24x7 support, hosting, and disaster recovery included on every plan with no start-up costs$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$2017 DOJ settlement of $155 million over EHR certification allegations remains part of its public history$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$Practice management and billing require stepping up to a higher-priced tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$Per-provider monthly pricing can add up quickly for larger multi-provider groups$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$Primarily built for ambulatory/outpatient care, not designed for large hospital-system deployments$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$How much does eClinicalWorks cost?$q$, $q$EHR Only starts at $449 per provider per month, EHR with Practice Management is $599 per provider per month, and Revenue Cycle Management as a Service is priced at 2.9% of practice collections.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$Who founded eClinicalWorks?$q$, $q$eClinicalWorks was founded in 1999 in Westborough, Massachusetts, by Girish Navani, who continues to serve as CEO, along with a small group of co-founders.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$Is eClinicalWorks cloud-based?$q$, $q$Yes, eClinicalWorks is a cloud-hosted platform, with hosting, maintenance, and disaster recovery included in its pricing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$What is the eClinicalWorks V12 platform?$q$, $q$V12, released in 2023, is eClinicalWorks' current-generation platform featuring a redesigned clinical workflow engine, the Eva AI virtual assistant, and expanded interoperability through PRISMA.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$What was the 2017 DOJ settlement about?$q$, $q$eClinicalWorks paid $155 million to settle allegations that it falsely obtained ONC certification for its EHR software, and completed a five-year Corporate Integrity Agreement as part of the settlement.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$Who typically uses eClinicalWorks?$q$, $q$It is used by solo and small-group physician practices, multi-specialty medical groups, federally qualified health centers, and other ambulatory care providers across the United States.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$Small independent physician practices$q$, $q$Solo and small-group practices use the EHR Only plan for certified clinical documentation and e-prescribing without a large upfront investment.$q$, $q$Independent physicians and small practices$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$Multi-specialty medical groups$q$, $q$Larger groups combine EHR with Practice Management to handle scheduling, billing, and clinical documentation in one platform.$q$, $q$Multi-specialty and multi-provider medical groups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$Practices outsourcing billing operations$q$, $q$Practices that want to avoid managing billing in-house use Revenue Cycle Management as a Service for a percentage of collections.$q$, $q$Practices seeking outsourced billing and RCM$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$EHR Only$q$, $q$$449/month per provider$q$, $q$Monthly$q$, NULL, $q$["Electronic health record","eClinicalMobile app","Patient portal","eClinicalMessenger","Document and referral management","24x7 support, hosting, and disaster recovery"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$EHR with Practice Management$q$, $q$$599/month per provider$q$, $q$Monthly$q$, NULL, $q$["All EHR Only features","Practice management module","Billing implementation services"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$RCM as a Service$q$, $q$2.9% of practice collections$q$, $q$Percentage of collections$q$, NULL, $q$["Claims creation and processing","Denial and rejection management","Appeals handling","Accounts-receivable visibility","Full EHR feature set included"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$eClinicalWorks is a cloud-based electronic health record and practice management platform founded in 1999 in Westborough, Massachusetts, by Girish Navani, who remains CEO. It is the largest privately held ambulatory EHR vendor in the United States, used by more than 850,000 physicians across over 180,000 facilities.$q$, $q$The company reported approximately $900 million in revenue for 2024 and released its current V12 platform in 2023, featuring a redesigned clinical workflow engine and an AI virtual assistant called Eva.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform includes an electronic health record, e-prescribing with formulary checking, a patient portal, secure patient messaging, document and referral management, and the eClinicalMobile app for accessing charts remotely.$q$, $q$It also offers eClinicalWorks P2P for health information exchange, eBO View for reporting and business intelligence, and registry reporting to support regulatory quality programs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$eClinicalWorks offers three published pricing tiers: EHR Only at $449 per provider per month, EHR with Practice Management at $599 per provider per month, and Revenue Cycle Management as a Service priced at 2.9% of practice collections.$q$, $q$All three plans include 24x7 support, maintenance, cloud hosting, and disaster recovery, with no start-up costs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('abea60cc-5f26-45e3-9696-3dec899a6984', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Embeddable storefront$q$, $q$Adds ecommerce functionality directly into an existing website, blog, or page without requiring a full site rebuild.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Multi-channel selling$q$, $q$Sells the same product catalog across a website, Instagram, Facebook, and online marketplaces from one dashboard.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Mobile management apps$q$, $q$Native iOS and Android apps let merchants manage orders, inventory, and settings from a phone.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$No transaction fees$q$, $q$Ecwid charges no setup or transaction fees on sales across every pricing tier.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Automated tax calculation$q$, $q$Calculates applicable sales tax automatically based on order destination on Venture tier and above.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Point-of-sale integration$q$, $q$The Unlimited plan connects online inventory with in-person POS systems for unified retail selling.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Abandoned cart recovery$q$, $q$Automatically emails customers who leave items in their cart without completing checkout, available from the Business tier.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Developer API$q$, $q$A documented API supports custom integrations and headless storefront development.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Low entry price starting at $5 per month with no transaction fees on any plan$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Can be embedded into an existing website rather than requiring a full rebuild$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Backed by publicly traded Lightspeed Commerce, giving it financial stability and a broader POS ecosystem$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Unlimited bandwidth and storage included even on the lowest-priced plan$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Product limits on Starter (10) and Venture (100) plans require upgrading as a catalog grows$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Point-of-sale integration is only available on the top Unlimited tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Multiple staff accounts require the Business plan or higher$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Less suited to merchants who want an all-in-one standalone site builder rather than an embedded widget$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$How much does Ecwid cost?$q$, $q$Ecwid's plans start at $5 per month for Starter and go up to $149 per month for Unlimited, with roughly 16% savings when billed annually.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Does Ecwid charge transaction fees?$q$, $q$No, Ecwid charges no setup fees and no transaction fees on sales across any of its pricing plans.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Who owns Ecwid?$q$, $q$Ecwid is owned by Lightspeed Commerce Inc. (NYSE: LSPD), a publicly traded Canadian ecommerce and point-of-sale company, following its 2021 acquisition.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Can I add Ecwid to a website I already have?$q$, $q$Yes, Ecwid is designed to be embedded into an existing website, such as one built on WordPress, Wix, or Squarespace, rather than requiring a new site.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Does Ecwid have a mobile app?$q$, $q$Yes, Ecwid offers native apps for iOS and Android for managing orders and inventory on the go.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Who founded Ecwid?$q$, $q$Ecwid was founded in 2009 by software engineers Ruslan Fazlyev and Yury Zaytsev, originally in Ulyanovsk, Russia.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Small businesses adding ecommerce to an existing site$q$, $q$Merchants with an established WordPress or Squarespace site embed Ecwid to start selling without rebuilding their web presence.$q$, $q$Small business owners with existing websites$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Social sellers on Instagram and Facebook$q$, $q$Merchants sell the same product catalog directly through social media shops alongside their website.$q$, $q$Social commerce sellers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Retailers unifying online and in-store sales$q$, $q$Brick-and-mortar retailers use the Unlimited plan's POS integration to sync online and in-person inventory through Lightspeed.$q$, $q$Retailers with physical store locations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Starter$q$, $q$$5/month$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 10 products","70+ storefront templates","Default Ecwid domain","Email support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Venture$q$, $q$$35/month ($29/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 100 products","Instagram and Facebook selling","Mobile management app","Live chat","Automated tax calculation","Custom checkout"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Business$q$, $q$$65/month ($49/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 2,500 products","Marketplace selling","Subscriptions support","2 staff accounts","Abandoned cart recovery","Wholesale pricing","Multi-lingual store"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$Unlimited$q$, $q$$149/month ($119/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited products","POS integration","Unlimited staff accounts","Priority support","500 promotions"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Ecwid, now branded Ecwid by Lightspeed, is a cloud ecommerce platform founded in 2009 by Ruslan Fazlyev and Yury Zaytsev, built around the idea of an embeddable storefront widget rather than a standalone website builder.$q$, $q$The company was acquired by publicly traded Lightspeed Commerce (NYSE: LSPD) in 2021 and now operates as part of the Lightspeed product family, headquartered in Montreal, Canada.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Ecwid lets merchants embed a store into an existing website built on WordPress, Wix, Squarespace, or a custom site, and sell simultaneously through Instagram, Facebook, and online marketplaces from one product catalog.$q$, $q$It includes mobile apps for iOS and Android, a documented API, automated tax calculation, abandoned cart recovery, wholesale pricing, and point-of-sale integration on higher tiers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Ecwid offers four tiers: Starter at $5/month (10 products), Venture at $35/month (100 products), Business at $65/month (2,500 products), and Unlimited at $149/month (unlimited products), each roughly 16% cheaper when billed annually.$q$, $q$There are no setup or transaction fees on any plan, and all tiers include unlimited bandwidth and storage.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('37d9ac64-b7a8-413c-8a11-4db621fc9e33', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
